 32→export class DataBackupService<T = unknown> {
 33→  private readonly primaryKey: string;
 34→  private readonly emergencyKey: string;
 35→  private readonly beforeUnloadKey: string;
 36→  private readonly metadataKey: string;
 37→  private readonly maxBackupAge: number = 7 * 24 * 60 * 60 * 1000; // 7 days
