 40→  constructor(
 41→    private readonly namespace: string,
 42→    private readonly validateData: (data: T) => boolean = () => true,
 43→  ) {
 44→    this.primaryKey = `gvBackup_${namespace}_primary`;
 45→    this.emergencyKey = `gvBackup_${namespace}_emergency`;
 46→    this.beforeUnloadKey = `gvBackup_${namespace}_beforeUnload`;
 47→    this.metadataKey = `gvBackup_${namespace}_metadata`;
 48→  }
 49→
 50→  /**
 51→   * Create a primary backup (called after successful save)
 52→   */
 53→  createPrimaryBackup(data: T): boolean {
 54→    try {
 55→      const backup = this.createBackupData(data);
 56→      localStorage.setItem(this.primaryKey, JSON.stringify(backup));
 57→      this.updateMetadata('primary', backup.metadata);
 58→      console.log(`[BackupService:${this.namespace}] Primary backup created`);
 59→      return true;
 60→    } catch (error) {
 61→      console.error(`[BackupService:${this.namespace}] Failed to create primary backup:`, error);
 62→      return false;
