 75→    } catch (error) {
 76→      console.error(`[BackupService:${this.namespace}] Failed to create emergency backup:`, error);
 77→      return false;
 78→    }
 79→  }
 80→
 81→  /**
 82→   * Create a beforeUnload backup (called when page is about to close)
 83→   */
 84→  private createBeforeUnloadBackup(data: T): boolean {
 85→    try {
 86→      const backup = this.createBackupData(data);
 87→      localStorage.setItem(this.beforeUnloadKey, JSON.stringify(backup));
 88→      console.log(`[BackupService:${this.namespace}] BeforeUnload backup created`);
 89→      return true;
 90→    } catch (error) {
 91→      console.error(
 92→        `[BackupService:${this.namespace}] Failed to create beforeUnload backup:`,
 93→        error,
 94→      );
 95→      return false;
 96→    }
