 99→  /**
100→   * Setup automatic beforeUnload backup
101→   */
102→  setupBeforeUnloadBackup(getDataFn: () => T): void {
103→    if (this.beforeUnloadHandler) {
104→      window.removeEventListener('beforeunload', this.beforeUnloadHandler);
105→    }
106→
107→    this.beforeUnloadHandler = () => {
108→      try {
109→        const data = getDataFn();
110→        this.createBeforeUnloadBackup(data);
111→      } catch (error) {
112→        console.error(`[BackupService:${this.namespace}] BeforeUnload handler error:`, error);
113→      }
114→    };
115→
116→    window.addEventListener('beforeunload', this.beforeUnloadHandler);
117→  }
