119→  /**
120→   * Attempt to recover data from backups
121→   * Priority: primary > emergency > beforeUnload
122→   */
123→  recoverFromBackup(): T | null {
124→    console.warn(`[BackupService:${this.namespace}] Attempting data recovery...`);
125→
126→    // Try primary backup first
127→    const primary = this.loadBackup(this.primaryKey, 'primary');
128→    if (primary) return primary;
129→
130→    // Try emergency backup
131→    const emergency = this.loadBackup(this.emergencyKey, 'emergency');
132→    if (emergency) return emergency;
133→
134→    // Try beforeUnload backup
135→    const beforeUnload = this.loadBackup(this.beforeUnloadKey, 'beforeUnload');
136→    if (beforeUnload) return beforeUnload;
137→
138→    console.error(`[BackupService:${this.namespace}] All backup recovery attempts failed`);
139→    return null;
